def step(self) -> list[dict]:                                                                                                                                                                                                
      model_msg = self.query()
      actions = model_msg.get("extra", {}).get("actions", [])
      if actions:                                                                                                                                                                                                              
          current = actions[0]
          if self._last_action is not None and self._actions_equal(current, self._last_action):                                                                                                                                
              if self._repeat_warned:
                  raise _RepeatedActionExit(                                                                                                                                                                                   
                      {
                          "role": "exit",                                                                                                                                                                                      
                          "content": "ERROR: Repeated action",
                          "extra": {"exit_status": "RepeatedAction", "submission": ""},
                      }                                                                                                                                                                                                        
                  )
              self._repeat_warned = True                                                                                                                                                                                       
              return self.add_messages(
                  self.model.format_message(
                      role="user",
                      content=REPEAT_WARNING,
                      extra={"repeat_warning": True},                                                                                                                                                                          
                  )
              )                                                                                                                                                                                                                
          self._last_action = current
          self._repeat_warned = False
      results = self.execute_actions(model_msg)
      self._trim_history()                                                                                                                                                                                                     
      return results

  @staticmethod   
  def _actions_equal(a: dict, b: dict) -> bool:
      return render_action(a).strip() == render_action(b).strip()

def _infer_answer_type(answer: str) -> str:
      """Infer the format type of a stored answer to enable type-matched retrieval."""
      import re
      stripped = answer.strip()
      if not stripped:
          return "other"
      # List: contains comma separator with multiple distinct tokens
      if "," in stripped and len(stripped.split(",")) >= 2:
          return "list"
      # Year: 4-digit number in plausible range
      if re.fullmatch(r"\d{4}", stripped) and 1000 <= int(stripped) <= 2100:
          return "year"

